firmware_template.source:
#include "duty_cycle.h"
#include <Arduino.h>
static uint8_t _pin=25;static float _duty=0;
void duty_setup(uint8_t p,uint32_t f){_pin=p;ledcAttach(p,f,12);Serial.printf("[duty] OK pin=%d freq=%lu\n",p,(unsigned long)f);}
void duty_set(float pct){_duty=constrain(pct,0,100);ledcWrite(_pin,(uint16_t)(_duty/100.0*4095));}
void duty_set_raw(uint16_t v){ledcWrite(_pin,v);_duty=v/4095.0*100;}
float duty_get(){return _duty;}
